SELECT COUNT(*)
FROM rental_records
WHERE year = 1;

SELECT season, year, COUNT(*) AS total_rentals
FROM rental_records
GROUP BY season, year;

SELECT DISTINCT season
FROM rental_records
ORDER BY season;

SELECT station_name
FROM station_records
WHERE station_type = 'premium';

SELECT COUNT(*) AS rental_count
FROM rental_records
WHERE season = 1 AND year = 0 AND peak_hours = 1;

SELECT rental_id, total_users, month, year
FROM rental_records
ORDER BY year, month;

SELECT user_type, total_rentals
FROM user_records
ORDER BY total_rentals DESC;
